PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?albumLabel
WHERE {
  ?album wdt:P658 ?track;
         rdfs:label ?albumLabel.
  ?track rdfs:label "Hand in Glove"@en.
  FILTER (LANG(?albumLabel) = "en")
}

